// Coleta os dados do nó SeparaNomes
const dados = $('Aggregate').all();

// Função para formatar a data como dd/mm/yyyy
function formatDate(date) {
    const day = String(date.getDate()).padStart(2, '0');
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = date.getFullYear();
    return `${day}/${month}/${year}`;
}

// Função para determinar a saudação com base na hora do dia
function getGreeting() {
    const hour = new Date().getHours();
    if (hour < 12) {
        return "Bom dia";
    } else if (hour < 18) {
        return "Boa tarde";
    } else {
        return "Boa noite";
    }
}

// Coleta a data atual e formata
const currentDate = new Date();
const formattedDate = formatDate(currentDate);

// Cria a saudação personalizada
const greeting = getGreeting();

// Inicia a mensagem
let mensagem = `${greeting} jovens 😁,\nAqui está a lista do relatório de INATIVOS do RH do dia ${formattedDate}:\n`;

// Extrai a lista de nomes do JSON
let nomes = [];
if (Array.isArray(dados) && dados.length > 0) {
    dados.forEach(item => {
        if (item.json && Array.isArray(item.json.data)) {
            item.json.data.forEach(entry => {
                if (entry.NOME) {
                    nomes.push(entry.NOME);
                }
            });
        }
    });
}

// Adiciona os nomes na mensagem
if (nomes.length > 0) {
    mensagem += `${nomes.join("\n")}\n\n`;
} else {
    mensagem += "Nenhum nome foi localizado na base de dados.\n\n";
}

// Retorna a mensagem formatada
return {
    textMessage: {
        msg: JSON.stringify(mensagem.trim())
    }
};

